package com.promonts.repository;import com.promonts.domain.notice.Notice;import com.promonts.domain.course.Course;import com.promonts.domain.user.User;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.List;@Repository public interface NoticeRepository extends JpaRepository<Notice, Long> { List<Notice> findByCourseOrderByCreatedAtDesc(Course course); List<Notice> findByAuthor(User author); List<Notice> findByCourseCodeOrderByCreatedAtDesc(String courseCode); }
